/*
仕様:
  画面デザインモック前段階として、仕様書 `04_ui_flow_screens.md` の主要画面IDをクリックで遷移確認する。

役割:
  - ExcaliburのScene上に起動確認用ラベルを表示する。
  - DOMオーバーレイで画面IDごとの仮カードと遷移ボタンを表示する。
  - 本物のゲームロジック、セーブ、ミニゲーム処理はまだ持たない。

更新時の注意:
  画面デザインや本実装ロジックを直接ここへ増やさず、ui/screenFlow 配下へ分離する。
*/
import * as ex from 'excalibur';
import { getInitialScreenIdFromSearch } from '../../ui/screenFlow/screenFlow';
import { createScreenFlowMock } from '../../ui/screenFlow/createScreenFlowMock';

export class TitleScene extends ex.Scene {
  private disposeScreenFlowMock: (() => void) | undefined;
  private statusLabel: ex.Label | undefined;

  override onInitialize(engine: ex.Engine): void {
    this.statusLabel = new ex.Label({
      text: 'Bard in Maghribal / screen flow mock',
      x: engine.drawWidth / 2,
      y: 72,
      font: new ex.Font({
        size: 34,
        family: 'sans-serif',
        textAlign: ex.TextAlign.Center
      })
    });
    this.add(this.statusLabel);

    const initialScreenId = getInitialScreenIdFromSearch(window.location.search);
    this.disposeScreenFlowMock = createScreenFlowMock({
      initialScreenId,
      onScreenChange: (screenId) => {
        if (this.statusLabel) {
          this.statusLabel.text = `Bard in Maghribal / ${screenId}`;
        }
      }
    });
  }

  override onDeactivate(): void {
    this.disposeScreenFlowMock?.();
    this.disposeScreenFlowMock = undefined;
  }
}
