export function getScreenDefinition(screenId: ScreenId): ScreenDefinition {
  return SCREEN_DEFINITIONS[screenId];
}

export function getInitialScreenIdFromSearch(search: string): ScreenId {
  const params = new URLSearchParams(search);
  const screen = params.get('screen');
  return isScreenId(screen) ? screen : 'title';
}

export function getTransitionTargets(screenId: ScreenId): readonly ScreenId[] {
  return SCREEN_DEFINITIONS[screenId].transitions.map((transition) => transition.target);
}
